import re
import collections

def evaluate_expression(expression):
    # Create cache with max size of 1000
    if not hasattr(evaluate_expression, 'cache'):
        evaluate_expression.cache = collections.defaultdict(float)
        evaluate_expression.cache_order = []

    # Check if result is in cache
    if expression in evaluate_expression.cache:
        return evaluate_expression.cache[expression]

    # Manage cache size (limit to 1000 entries)
    if len(evaluate_expression.cache_order) >= 1000:
        oldest = evaluate_expression.cache_order.pop(0)
        del evaluate_expression.cache[oldest]

    # Tokenize the expression
    tokens = re.findall(r'[\d\.]+|[+\-*/()]', expression)

    def parse_expression():
        return parse_addition()

    def parse_addition():
        left = parse_multiplication()
        while tokens and tokens[0] in ['+', '-']:
            op = tokens.pop(0)
            right = parse_multiplication()
            if op == '+':
                left += right
            else:  # op == '-'
                left -= right
        return left

    def parse_multiplication():
        left = parse_parentheses()
        while tokens and tokens[0] in ['*', '/']:
            op = tokens.pop(0)
            right = parse_parentheses()
            if op == '*':
                left *= right
            else:  # op == '/'
                left /= right
        return left

    def parse_parentheses():
        if tokens and tokens[0] == '(':
            tokens.pop(0)  # Remove '('
            result = parse_expression()
            tokens.pop(0)  # Remove ')'
            return result
        else:
            return parse_number()

    def parse_number():
        return float(tokens.pop(0))

    # Evaluate the expression
    result = parse_expression()

    # Store in cache
    evaluate_expression.cache[expression] = result
    evaluate_expression.cache_order.append(expression)

    return result

import java.time.Instant;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public class SessionManager {
    private static final int MAX_SESSIONS = 500;
    private static final long SESSION_TIMEOUT_MINUTES = 30;
    private static final ConcurrentHashMap<String, Instant> activeSessions = new ConcurrentHashMap<>();

    public static boolean addSession(String sessionId) {
        // Remove expired sessions first
        removeExpiredSessions();

        // Check if max session limit reached
        if (activeSessions.size() >= MAX_SESSIONS) {
            return false;
        }

        // Add new session with current timestamp
        activeSessions.put(sessionId, Instant.now());
        return true;
    }

    public static boolean isSessionActive(String sessionId) {
        Instant lastActivity = activeSessions.get(sessionId);
        if (lastActivity == null) {
            return false;
        }

        // Check if session has expired
        if (isSessionExpired(lastActivity)) {
            activeSessions.remove(sessionId);
            return false;
        }

        // Update the timestamp for the active session
        activeSessions.put(sessionId, Instant.now());
        return true;
    }

    public static void removeSession(String sessionId) {
        activeSessions.remove(sessionId);
    }

    public static int getActiveSessionCount() {
        removeExpiredSessions();
        return activeSessions.size();
    }

    private static boolean isSessionExpired(Instant lastActivity) {
        long minutesElapsed = java.time.Duration.between(lastActivity, Instant.now()).toMinutes();
        return minutesElapsed >= SESSION_TIMEOUT_MINUTES;
    }

    private static void removeExpiredSessions() {
        Instant currentTime = Instant.now();

        activeSessions.entrySet().removeIf(entry -> {
            long minutesElapsed = java.time.Duration.between(entry.getValue(), currentTime).toMinutes();
            return minutesElapsed >= SESSION_TIMEOUT_MINUTES;
        });
    }
}

import java.util.*;

public class SortedListMerger {

    public static class ListNode {
        int val;
        ListNode next;

        ListNode() {}
        ListNode(int val) { this.val = val; }
        ListNode(int val, ListNode next) { this.val = val; this.next = next; }
    }

    public static LinkedList<Integer> mergeKLists(ListNode[] lists) {
        LinkedList<Integer> result = new LinkedList<>();

        // Handle empty input
        if (lists == null || lists.length == 0) {
            return result;
        }

        // Create a min heap (priority queue)
        PriorityQueue<ListNode> minHeap = new PriorityQueue<>((a, b) -> a.val - b.val);

        // Add the first node of each list to the heap
        for (ListNode list : lists) {
            if (list != null) {
                minHeap.offer(list);
            }
        }

        int count = 0;

        // Process nodes from the heap
        while (!minHeap.isEmpty() && count < 10000) {
            // Extract the smallest node
            ListNode node = minHeap.poll();
            result.add(node.val);
            count++;

            // Add the next node from the same list to the heap
            if (node.next != null) {
                minHeap.offer(node.next);
            }
        }

        return result;
    }
}

