        srand(time(nullptr));

        for (int i = 0; i < size; i++) {
            for (int j = 0; j < size; j++) {
                int currentId = getID(i, j);

                // Connect to right neighbor
                if (j < size - 1) {
                    int rightId = getID(i, j + 1);
                    int time = 1 + rand() % 10;
                    adjacencyList[currentId].push_back({rightId, time});
                    adjacencyList[rightId].push_back({currentId, time});
                }

                // Connect to bottom neighbor
                if (i < size - 1) {
                    int bottomId = getID(i + 1, j);
                    int time = 1 + rand() % 10;
                    adjacencyList[currentId].push_back({bottomId, time});
                    adjacencyList[bottomId].push_back({currentId, time});
                }
            }
        }
    }

    // Find shortest path using Dijkstra's algorithm with dynamic programming
    vector<int> findShortestPath(int startId, int endId) {
        // Distance array for dynamic programming
        vector<int> distance(gridSize * gridSize, numeric_limits<int>::max());
        vector<int> previous(gridSize * gridSize, -1);

        // Priority queue: {distance, node_id}
        priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

        // Unordered set to track visited nodes and prevent cycles
        unordered_set<int> visited;

        // Initialize start node
        distance[startId] = 0;
        pq.push({0, startId});

        while (!pq.empty()) {
            int currentDist = pq.top().first;
            int currentId = pq.top().second;
            pq.pop();

            // Early termination if we reached the destination
            if (currentId == endId) {
                break;
            }

            // Skip if already visited (prevents cycles)
            if (visited.find(currentId) != visited.end()) {
                continue;
            }

            // Mark as visited
            visited.insert(currentId);

            // Skip if current distance is outdated
            if (currentDist > distance[currentId]) {
                continue;
            }

            // Process all neighbors
            if (adjacencyList.find(currentId) != adjacencyList.end()) {
                for (const auto& neighbor : adjacencyList[currentId]) {
                    int neighborId = neighbor.first;
                    int travelTime = neighbor.second;

                    // Skip if neighbor already visited
                    if (visited.find(neighborId) != visited.end()) {
                        continue;
                    }

                    int newDist = currentDist + travelTime;

                    // Dynamic programming: update if we found a better path
                    if (newDist < distance[neighborId]) {
                        distance[neighborId] = newDist;
                        previous[neighborId] = currentId;
                        pq.push({newDist, neighborId});
                    }
                }
            }
        }

        // Reconstruct path
        vector<int> path;
        for (int at = endId; at != -1; at = previous[at]) {
            path.push_back(at);
        }
        reverse(path.begin(), path.end());

        // Return empty path if no route found
        if (path.empty() || path[0] != startId) {
            return {};
        }

        return path;
