public:
    UrbanGrid(int n) : size(n) {
        grid.resize(n, vector<int>(n, 1));
        // Initialize with random weights 1-10 for realistic travel times
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
