        // DP table to store minimum distances
        vector<vector<int>> dp(size, vector<int>(size, INT_MAX));
        vector<vector<pair<int, int>>> parent(size, vector<pair<int, int>>(size, {-1, -1}));

        // Priority queue for Dijkstra with DP optimization
        priority_queue<pair<int, pair<int, int>>, vector<pair<int, pair<int, int>>>, greater<>> pq;

        // Unordered set to track visited nodes and prevent cycles
        unordered_set<long long> visited;

        // Helper function to convert coordinates to hash
        auto getHash = [](int x, int y) -> long long {
            return ((long long)x << 32) | y;
        };

        // Directions: right, down, left, up
        int dx[] = {0, 1, 0, -1};
        int dy[] = {1, 0, -1, 0};

        // Initialize starting point
        dp[startX][startY] = grid[startX][startY];
        pq.push({dp[startX][startY], {startX, startY}});

        while (!pq.empty()) {
            auto [dist, pos] = pq.top();
            pq.pop();

            int x = pos.first, y = pos.second;
            long long hash = getHash(x, y);

            // Skip if already visited (prevents cycles)
            if (visited.count(hash)) continue;
            visited.insert(hash);

            // Early termination if reached destination
            if (x == endX && y == endY) break;

            // Skip if current distance is outdated
            if (dist > dp[x][y]) continue;

            // Explore all 4 directions
            for (int i = 0; i < 4; i++) {
                int nx = x + dx[i];
                int ny = y + dy[i];

                // Check bounds
                if (nx < 0 || nx >= size || ny < 0 || ny >= size) continue;

                long long nextHash = getHash(nx, ny);
                if (visited.count(nextHash)) continue;

                int newDist = dp[x][y] + grid[nx][ny];

                // DP optimization: update if found better path
                if (newDist < dp[nx][ny]) {
                    dp[nx][ny] = newDist;
                    parent[nx][ny] = {x, y};
                    pq.push({newDist, {nx, ny}});
                }
