type TemperatureBuffer struct {
	buffer      *bytes.Buffer
	readings    []float64
	capacity    int
	totalValues int
}

// NewTemperatureBuffer creates a new temperature buffer with specified capacity
func NewTemperatureBuffer(capacity int) *TemperatureBuffer {
	return &TemperatureBuffer{
		buffer:      &bytes.Buffer{},
		readings:    make([]float64, 0, capacity),
		capacity:    capacity,
		totalValues: 0,
	}
}

// Add adds a new temperature reading to the buffer
func (tb *TemperatureBuffer) Add(value float64) error {
	if tb.totalValues >= 1000 {
		return fmt.Errorf("buffer overflow: maximum 1000 readings exceeded")
	}

	// Store reading in slice for calculations
	if len(tb.readings) >= tb.capacity {
		// Remove oldest reading
		tb.readings = tb.readings[1:]
	}
	tb.readings = append(tb.readings, value)

	// Store in bytes.Buffer for logging/serialization
	data := fmt.Sprintf("%.2f,", value)
	tb.buffer.WriteString(data)

	tb.totalValues++
	return nil
}

// Average calculates the moving average of current readings
func (tb *TemperatureBuffer) Average() (float64, error) {
	if len(tb.readings) == 0 {
		return 0, fmt.Errorf("buffer is empty")
	}

	sum := 0.0
	for _, reading := range tb.readings {
		sum += reading
	}
	return sum / float64(len(tb.readings)), nil
}

// Size returns the current number of readings in buffer
func (tb *TemperatureBuffer) Size() int {
	return len(tb.readings)
}

// TotalValues returns the total number of values processed
func (tb *TemperatureBuffer) TotalValues() int {
	return tb.totalValues
}

