func NewSensorBuffer(capacity int, maxEntries int) *SensorBuffer {
	return &SensorBuffer{
		buffer:      new(bytes.Buffer),
		readings:    make([]float64, 0, capacity),
		capacity:    capacity,
		totalValues: 0,
		maxEntries:  maxEntries,
	}
}

// Add adds a new temperature reading to the buffer
func (sb *SensorBuffer) Add(value float64) error {
	if sb.totalValues >= sb.maxEntries {
		return fmt.Errorf("buffer overflow: maximum %d readings exceeded", sb.maxEntries)
	}

	// Store reading in slice for calculations
	if len(sb.readings) >= sb.capacity {
		// Remove oldest reading
		sb.readings = sb.readings[1:]
	}
	sb.readings = append(sb.readings, value)

	// Store in bytes.Buffer for logging
	fmt.Fprintf(sb.buffer, "%.2f,", value)

	sb.totalValues++
	return nil
}

// Average calculates the moving average of current readings
func (sb *SensorBuffer) Average() (float64, error) {
	if len(sb.readings) == 0 {
		return 0, fmt.Errorf("buffer is empty")
	}

	sum := 0.0
	for _, reading := range sb.readings {
		sum += reading
	}
	return sum / float64(len(sb.readings)), nil
}

// Size returns the current number of readings in buffer
func (sb *SensorBuffer) Size() int {
	return len(sb.readings)
}

// TotalValues returns the total number of values processed
func (sb *SensorBuffer) TotalValues() int {
	return sb.totalValues
}

// GetBuffer returns the underlying bytes.Buffer
func (sb *SensorBuffer) GetBuffer() *bytes.Buffer {
	return sb.buffer
}

// Clear empties the buffer
func (sb *SensorBuffer) Clear() {
	sb.buffer.Reset()
	sb.readings = sb.readings[:0]
	sb.totalValues = 0
}

// Sensor represents a temperature sensor with buffer management
type Sensor struct {
	ID     string
	buffer *SensorBuffer
	logger *log.Logger
}

// NewSensor creates a new sensor with specified ID and buffer capacity
func NewSensor(id string, bufferCapacity int, maxEntries int, logger *log.Logger) *Sensor {
	return &Sensor{
		ID:     id,
		buffer: NewSensorBuffer(bufferCapacity, maxEntries),
		logger: logger,
	}
}

// ProcessReading processes a temperature reading with comprehensive error handling
func (s *Sensor) ProcessReading(temperature float64) error {
	s.logger.Printf("INFO: Sensor %s received temperature reading: %.2f", s.ID, temperature)

	// Validate temperature range (basic sanity check)
	if temperature < -100 || temperature > 200 {
		err := fmt.Errorf("temperature out of valid range: %.2f", temperature)
		s.logger.Printf("ERROR: Sensor %s - %v", s.ID, err)
		return err
	}

	// Add reading to buffer
	if err := s.buffer.Add(temperature); err != nil {
		s.logger.Printf("ERROR: Sensor %s failed to add reading: %v", s.ID, err)
		return err
	}

	// Calculate and log moving average
	avg, err := s.buffer.Average()
	if err != nil {
		s.logger.Printf("ERROR: Failed to calculate average for sensor %s: %v", s.ID, err)
		return err
	}

	s.logger.Printf("INFO: Sensor %s current moving average: %.2f (from %d readings, total processed: %d)", 
		s.ID, avg, s.buffer.Size(), s.buffer.TotalValues())

	return nil
}

// GetStatistics returns current sensor statistics
func (s *Sensor) GetStatistics() (float64, int, int, error) {
	avg, err := s.buffer.Average()
	if err != nil {
		return 0, 0, 0, err
	}
	return avg, s.buffer.Size(), s.buffer.TotalValues(), nil
}

