		heap.Fix(lp.entryHeap, 0) // Update heap
		return
	}

	if len(lp.entryCounts) < lp.maxEntries {
		entry := &LogEntry{text: line, count: 1}
		lp.entryCounts[line] = entry
		heap.Push(lp.entryHeap, entry)
	} else {
		if lp.entryHeap.Len() > 0 {
			minEntry := heap.Pop(lp.entryHeap).(*LogEntry)
			if minEntry.count < 2 {
				delete(lp.entryCounts, minEntry.text)
				entry := &LogEntry{text: line, count: 1}
				lp.entryCounts[line] = entry
				heap.Push(lp.entryHeap, entry)
			} else {
				heap.Push(lp.entryHeap, minEntry)
				lp.discardedCount++
			}
		} else {
			lp.discardedCount++
		}
	}
}

func (lp *LogProcessor) processFile(filePath string, wg *sync.WaitGroup) {
	defer wg.Done()

	file, err := os.Open(filePath)
	if err != nil {
		fmt.Printf("Error opening file %s: %v\n", filePath, err)
		return
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 0, 64*1024), 1024*1024)

	for scanner.Scan() {
		lp.processLine(scanner.Text())
	}

	if err := scanner.Err(); err != nil {
		fmt.Printf("Error reading file %s: %v\n", filePath, err)
	}
}

func main() {
	if len(os.Args) < 2 {
		fmt.Println("Usage: ./logprocessor <directory or file paths...>")
		os.Exit(1)
	}

	processor := NewLogProcessor(20000)
	var wg sync.WaitGroup
	filesChan := make(chan string, 100)

	// Start worker goroutines
	workerCount := 8
	for i := 0; i < workerCount; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for filePath := range filesChan {
				var fileWg sync.WaitGroup
				fileWg.Add(1)
				processor.processFile(filePath, &fileWg)
				fileWg.Wait()
			}
		}()
	}

	// Find files to process
	for _, arg := range os.Args[1:] {
		fileInfo, err := os.Stat(arg)
		if err != nil {
			fmt.Printf("Error accessing %s: %v\n", arg, err)
			continue
		}

		if fileInfo.IsDir() {
			err := filepath.Walk(arg, func(path string, info os.FileInfo, err error) error {
				if err != nil {
					return err
				}

				if !info.IsDir() {
					filesChan <- path
				}
				return nil
			})

			if err != nil {
				fmt.Printf("Error walking directory %s: %v\n", arg, err)
			}
		} else {
			filesChan <- arg
		}
	}

	close(filesChan)
	wg.Wait()

	// Print results
	processor.mutex.RLock()
	defer processor.mutex.RUnlock()

	fmt.Printf("Processed %d log entries\n", processor.processedCount)
	fmt.Printf("Unique entries tracked: %d\n", len(processor.entryCounts))
	fmt.Printf("Entries discarded (exceeded limit): %d\n", processor.discardedCount)

	// Get top entries
	type EntryCount struct {
		text  string
		count int
	}

	entries := make([]EntryCount, 0, len(processor.entryCounts))
	for text, entry := range processor.entryCounts {
		entries = append(entries, EntryCount{text, entry.count})
	}

	// Simple bubble sort for top 10 (small enough to not need a more complex sort)
	for i := 0; i < len(entries) && i < 10; i++ {
		maxIdx := i
		for j := i + 1; j < len(entries); j++ {
			if entries[j].count > entries[maxIdx].count {
				maxIdx = j
			}
		}
		entries[i], entries[maxIdx] = entries[maxIdx], entries[i]
	}

	fmt.Println("\nTop log entries by count:")
	for i := 0; i < len(entries) && i < 10; i++ {
		fmt.Printf("%d occurrences: %s\n", entries[i].count, entries[i].text)
	}
}
