import numpy as np
from typing import Dict, List, Tuple

def floyd_warshall(graph: Dict[int, Dict[int, float]]) -> Dict[int, Dict[int, float]]:
    # Extract all unique nodes from the graph
    nodes = list(set(list(graph.keys()) + [v for sublist in [list(neighbors.keys()) for neighbors in graph.values()] for v in sublist]))
    n = len(nodes)

    # Create a mapping from node ID to index
    node_to_idx = {nodes[i]: i for i in range(n)}

    # Initialize distance matrix with infinity
    dist = np.full((n, n), float('inf'))

    # Set distance from node to itself as 0
    for i in range(n):
        dist[i, i] = 0

    # Fill distance matrix with direct edge weights
    for u in graph:
        for v, weight in graph[u].items():
            dist[node_to_idx[u], node_to_idx[v]] = weight

    # Create a queue to store pairs of nodes for computation
    computation_queue = queue.Queue(maxsize=1000)

    # Initialize queue with all pairs of nodes
    for k in range(n):
        for i in range(n):
            for j in range(n):
                if i != j and i != k and j != k:
                    # Only add to queue if we haven't yet exceeded capacity
                    if computation_queue.qsize() < 1000:
                        computation_queue.put((i, j, k))

    # Process the queue
    while not computation_queue.empty():
        i, j, k = computation_queue.get()
        # Check if path through k is shorter
        if dist[i, k] + dist[k, j] < dist[i, j]:
            dist[i, j] = dist[i, k] + dist[k, j]

    # Convert the result back to dictionary format
    result = {nodes[i]: {} for i in range(n)}
    for i in range(n):
        for j in range(n):
            if i != j and dist[i, j] != float('inf'):
                result[nodes[i]][nodes[j]] = dist[i, j]

    return result

