struct MedianStream {
    elements: BTreeMap<i32, usize>,
    total_count: usize,
}

impl MedianStream {
    fn new() -> Self {
        MedianStream {
            elements: BTreeMap::new(),
            total_count: 0,
        }
    }

    fn add(&mut self, value: i32) {
        if self.total_count >= 5000 {
            return;
        }

        *self.elements.entry(value).or_insert(0) += 1;
        self.total_count += 1;
    }

    fn get_median(&self) -> f64 {
        if self.total_count == 0 {
            return 0.0;
        }

        let is_odd = self.total_count % 2 == 1;
        let mid1_pos = (self.total_count + 1) / 2;
        let mid2_pos = if is_odd { mid1_pos } else { mid1_pos + 1 };

        let mut count = 0;
        let mut mid1_val = None;
        let mut mid2_val = None;

        for (&value, &freq) in &self.elements {
            count += freq;

            if count >= mid1_pos && mid1_val.is_none() {
                mid1_val = Some(value);
            }

            if count >= mid2_pos {
                mid2_val = Some(value);
                break;
            }
        }

        match (mid1_val, mid2_val) {
            (Some(v1), Some(v2)) => (v1 as f64 + v2 as f64) / 2.0,
            (Some(v), None) => v as f64,
            _ => 0.0,
        }
    }

    fn size(&self) -> usize {
        self.total_count
    }
}

