use std::collections::BTreeMap;
use std::io::{self, BufRead};

struct MedianStream {
    elements: BTreeMap<i32, usize>,
    total_count: usize,
    max_size: usize,
}

impl MedianStream {
    fn new(max_size: usize) -> Self {
        MedianStream {
            elements: BTreeMap::new(),
            total_count: 0,
            max_size,
        }
    }

    fn add(&mut self, value: i32) -> bool {
        if self.total_count >= self.max_size {
            return false;
        }

        *self.elements.entry(value).or_insert(0) += 1;
        self.total_count += 1;
        true
    }

    fn get_median(&self) -> Option<f64> {
        if self.total_count == 0 {
            return None;
        }

        let is_odd = self.total_count % 2 == 1;
        let mid1_pos = (self.total_count + 1) / 2;
        let mid2_pos = if is_odd { mid1_pos } else { mid1_pos + 1 };

        let mut count = 0;
        let mut mid1_val = None;
        let mut mid2_val = None;

        for (&value, &freq) in &self.elements {
            let new_count = count + freq;

            if mid1_val.is_none() && new_count >= mid1_pos {
                mid1_val = Some(value);
            }

            if new_count >= mid2_pos {
                mid2_val = Some(value);
                break;
            }

            count = new_count;
        }

        match (mid1_val, mid2_val) {
            (Some(v1), Some(v2)) => Some((v1 as f64 + v2 as f64) / 2.0),
            _ => None,
        }
    }

    fn size(&self) -> usize {
        self.total_count
    }
}

fn main() {
    let mut stream = MedianStream::new(5000);
    let stdin = io::stdin();

    println!("Integer Stream Median Calculator");
    println!("Commands:");
    println!("  add <value>  - Add an integer to the stream");
    println!("  median       - Calculate the current median");
    println!("  size         - Show the current size of the stream");
    println!("  exit         - Exit the application");

    for line in stdin.lock().lines() {
        if let Ok(input) = line {
            let parts: Vec<&str> = input.split_whitespace().collect();

            if parts.is_empty() {
                continue;
            }

            match parts[0] {
                "add" => {
                    if parts.len() < 2 {
                        println!("Please provide a value to add");
                        continue;
                    }

                    match parts[1].parse::<i32>() {
                        Ok(value) => {
                            if stream.add(value) {
                                println!("Added {} to the stream", value);
                            } else {
                                println!("Maximum stream size (5000) reached");
                            }
                        },
                        Err(_) => println!("Invalid integer value"),
                    }
                },
                "median" => {
                    match stream.get_median() {
                        Some(median) => println!("Current median: {}", median),
                        None => println!("Stream is empty"),
                    }
                },
                "size" => {
                    println!("Current stream size: {}", stream.size());
                },
                "exit" => {
                    println!("Exiting...");
                    break;
                },
                _ => {
                    println!("Unknown command");
                }
            }
        }
    }
}
